import{_ as i,o as t,c as l,ae as e}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"深入剖析 RAG：Chunking、Hybrid Retrieval、Rerank 与上下文组装","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/rag-deep-dive.md","filePath":"ai-tutorial/rag-deep-dive.md"}'),r={name:"ai-tutorial/rag-deep-dive.md"};function n(s,a,d,o,h,p){return t(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="深入剖析-rag-chunking、hybrid-retrieval、rerank-与上下文组装" tabindex="-1">深入剖析 RAG：Chunking、Hybrid Retrieval、Rerank 与上下文组装 <a class="header-anchor" href="#深入剖析-rag-chunking、hybrid-retrieval、rerank-与上下文组装" aria-label="Permalink to &quot;深入剖析 RAG：Chunking、Hybrid Retrieval、Rerank 与上下文组装&quot;">​</a></h1><blockquote><p>很多团队第一次把 RAG 跑通时，都会先开心五分钟，然后开始怀疑人生：明明都检索到了，怎么还是答不对？ 这类挫败感特别真实，因为系统表面上没报错，召回分数看起来也不低，页面上甚至还能展示引用来源。可真正的问题往往藏在更前面：文档是怎么切的、候选是怎么召回的、噪声是怎么混进去的、最后又是怎么被一股脑塞进上下文的。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>为什么 Naive RAG 经常出现“能召回、答不对”</li><li>文档切块、混合检索、重排和上下文组装各解决什么问题</li><li>怎样用更工程化的方式评估 RAG 系统</li><li>一套更适合企业知识场景的链路设计</li></ul></div><h2 id="_1-rag-失败-通常不是失败在-生成-而是失败在-供料" tabindex="-1">1. RAG 失败，通常不是失败在“生成”，而是失败在“供料” <a class="header-anchor" href="#_1-rag-失败-通常不是失败在-生成-而是失败在-供料" aria-label="Permalink to &quot;1. RAG 失败，通常不是失败在“生成”，而是失败在“供料”&quot;">​</a></h2><p>RAG 的本质是把生成建立在外部事实之上。但从用户问题到最终答案，中间至少有四道关：</p><ol><li>文档被怎么切块</li><li>候选结果怎么召回</li><li>候选结果怎么排序</li><li>最终上下文怎么组装</li></ol><p>任何一环做得粗糙，最终答案都会受影响。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;用户问题&quot;] --&gt; R1[&quot;查询改写&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R1 --&gt; R2[&quot;多路召回&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R2 --&gt; R3[&quot;重排&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R3 --&gt; R4[&quot;上下文组装&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R4 --&gt; G[&quot;模型生成&quot;]</span></span></code></pre></div><h2 id="_2-chunking-切块方式决定了能否拿回完整语义" tabindex="-1">2. Chunking：切块方式决定了能否拿回完整语义 <a class="header-anchor" href="#_2-chunking-切块方式决定了能否拿回完整语义" aria-label="Permalink to &quot;2. Chunking：切块方式决定了能否拿回完整语义&quot;">​</a></h2><p>最常见但也最粗糙的做法，是按固定长度切块，比如每 500 个字切一段。这在工程上简单，但代价也明显：</p><ul><li>句子可能被硬切断</li><li>标题和正文被拆开</li><li>表格或条款上下文丢失</li><li>召回命中了片段，但片段本身无法支撑回答</li></ul><h3 id="_2-1-常见切块策略对比" tabindex="-1">2.1 常见切块策略对比 <a class="header-anchor" href="#_2-1-常见切块策略对比" aria-label="Permalink to &quot;2.1 常见切块策略对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>策略</th><th>优点</th><th>问题</th><th>适用场景</th></tr></thead><tbody><tr><td>固定长度切块</td><td>实现简单</td><td>语义经常断裂</td><td>原型验证</td></tr><tr><td>重叠切块</td><td>缓解边界断裂</td><td>冗余增加</td><td>通用文本</td></tr><tr><td>结构化切块</td><td>保留标题、段落、表格关系</td><td>实现更复杂</td><td>Markdown、HTML、制度文档</td></tr><tr><td>语义切块</td><td>更贴近自然语义单元</td><td>依赖切分质量</td><td>长文、解释型材料</td></tr><tr><td>Parent-Child 切块</td><td>检索精度和上下文完整度兼顾</td><td>需要双层索引</td><td>企业知识库</td></tr></tbody></table><h3 id="_2-2-为什么-parent-child-很实用" tabindex="-1">2.2 为什么 Parent-Child 很实用 <a class="header-anchor" href="#_2-2-为什么-parent-child-很实用" aria-label="Permalink to &quot;2.2 为什么 Parent-Child 很实用&quot;">​</a></h3><p>一种在企业场景里很常见的做法是：</p><ul><li>写入时把文档切成较小子块，便于精确召回</li><li>同时保留较大父块，便于回答时补足背景</li></ul><p>检索时命中的是子块，最终送给模型的可以是子块所在的父块或父块摘要。这样能兼顾：</p><ul><li>检索精度</li><li>上下文完整性</li><li>Token 成本控制</li></ul><h2 id="_3-retrieval-向量检索不是全部答案" tabindex="-1">3. Retrieval：向量检索不是全部答案 <a class="header-anchor" href="#_3-retrieval-向量检索不是全部答案" aria-label="Permalink to &quot;3. Retrieval：向量检索不是全部答案&quot;">​</a></h2><p>向量检索擅长找“语义相近”的内容，但它不一定擅长找：</p><ul><li>精确编号</li><li>稀有术语</li><li>合同条款编号</li><li>人名、设备号、SKU 这类专有标识</li></ul><p>这也是为什么很多生产系统会采用混合检索。</p><h3 id="_3-1-hybrid-retrieval-的基本思路" tabindex="-1">3.1 Hybrid Retrieval 的基本思路 <a class="header-anchor" href="#_3-1-hybrid-retrieval-的基本思路" aria-label="Permalink to &quot;3.1 Hybrid Retrieval 的基本思路&quot;">​</a></h3><p>常见做法是同时走两路：</p><ul><li><strong>Dense Retrieval</strong>：向量检索，找语义相关</li><li><strong>Sparse Retrieval</strong>：关键词检索，例如 BM25，找字面命中</li></ul><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;用户问题&quot;] --&gt; A[&quot;向量检索&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q --&gt; B[&quot;关键词检索&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; C[&quot;候选集合合并&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;重排&quot;]</span></span></code></pre></div><p>这样做的优势很直接：</p><ul><li>语义召回负责“意思相近”</li><li>关键词召回负责“字面必须命中”</li></ul><p>尤其在企业资料里，很多关键事实恰恰藏在编号、术语和固定表达中，单靠向量检索并不稳。</p><h2 id="_4-rerank-把-粗相关-变成-高相关" tabindex="-1">4. Rerank：把“粗相关”变成“高相关” <a class="header-anchor" href="#_4-rerank-把-粗相关-变成-高相关" aria-label="Permalink to &quot;4. Rerank：把“粗相关”变成“高相关”&quot;">​</a></h2><p>初次召回拿回来的候选集，通常只是“可能有用”。如果直接把这些内容全部丢给大模型，很容易出现两类问题：</p><ul><li>噪声太多，真正有用信息被淹没</li><li>候选太长，模型注意力分散</li></ul><p>因此 Rerank 的作用，是在更小的候选集上做更精细的相关性排序。</p><h3 id="_4-1-为什么需要单独的重排层" tabindex="-1">4.1 为什么需要单独的重排层 <a class="header-anchor" href="#_4-1-为什么需要单独的重排层" aria-label="Permalink to &quot;4.1 为什么需要单独的重排层&quot;">​</a></h3><p>因为检索和重排追求的不是同一件事：</p><ul><li>检索追求高召回，宁愿多拿一点</li><li>重排追求高精度，要把最有用的结果排到前面</li></ul><p>在工程上，这通常意味着：</p><ol><li>先用相对便宜的检索方法拿回 Top N</li><li>再用更精细的模型或规则，把 Top N 排序</li><li>最终只保留少量高价值片段送给生成模型</li></ol><h3 id="_4-2-rerank-解决的是-排序问题-不是-真理问题" tabindex="-1">4.2 Rerank 解决的是“排序问题”，不是“真理问题” <a class="header-anchor" href="#_4-2-rerank-解决的是-排序问题-不是-真理问题" aria-label="Permalink to &quot;4.2 Rerank 解决的是“排序问题”，不是“真理问题”&quot;">​</a></h3><p>要注意，重排不能修复所有问题。如果切块本身已经断裂、召回就没命中关键内容，Rerank 也只能在错误候选里挑“相对更像正确的”。</p><h2 id="_5-context-assembly-最后一步经常被低估" tabindex="-1">5. Context Assembly：最后一步经常被低估 <a class="header-anchor" href="#_5-context-assembly-最后一步经常被低估" aria-label="Permalink to &quot;5. Context Assembly：最后一步经常被低估&quot;">​</a></h2><p>即使你拿到了不错的候选结果，如何把这些结果送进模型也很关键。</p><p>常见错误包括：</p><ul><li>原样拼接所有候选</li><li>不保留来源信息</li><li>不区分主证据和补充证据</li><li>把长片段全文塞入，导致上下文污染</li></ul><h3 id="_5-1-更好的上下文组装原则" tabindex="-1">5.1 更好的上下文组装原则 <a class="header-anchor" href="#_5-1-更好的上下文组装原则" aria-label="Permalink to &quot;5.1 更好的上下文组装原则&quot;">​</a></h3><ul><li>优先放最相关证据</li><li>保留来源标识，便于前端展示引用</li><li>把重复内容合并</li><li>对特别长的候选先做压缩或摘要</li><li>静态背景和直接证据分层组织</li></ul><p>一个更实用的组装模板可能是：</p><ol><li>问题重写后的检索意图</li><li>Top 1 到 Top 3 直接证据</li><li>必要的补充背景</li><li>输出要求，例如“若证据不足请明确说明”</li></ol><h2 id="_6-如何评估一条-rag-链路" tabindex="-1">6. 如何评估一条 RAG 链路 <a class="header-anchor" href="#_6-如何评估一条-rag-链路" aria-label="Permalink to &quot;6. 如何评估一条 RAG 链路&quot;">​</a></h2><p>RAG 项目很容易只看最终回答好不好，但这样很难定位问题。更稳妥的方式是分层评估。</p><table tabindex="0"><thead><tr><th>层次</th><th>要看什么</th></tr></thead><tbody><tr><td>切块层</td><td>是否保留了语义边界</td></tr><tr><td>召回层</td><td>关键证据是否进入候选集</td></tr><tr><td>重排层</td><td>关键证据是否排在前面</td></tr><tr><td>组装层</td><td>送给模型的上下文是否简洁且充分</td></tr><tr><td>生成层</td><td>是否忠实引用证据，是否承认证据不足</td></tr></tbody></table><p>如果只看最终答案，就会把所有问题都误判成“模型不够强”。</p><h2 id="_7-企业场景里的推荐链路" tabindex="-1">7. 企业场景里的推荐链路 <a class="header-anchor" href="#_7-企业场景里的推荐链路" aria-label="Permalink to &quot;7. 企业场景里的推荐链路&quot;">​</a></h2><p>对大多数企业知识问答项目，一个更稳妥的中间形态通常是：</p><ol><li>文档解析与清洗</li><li>结构化切块或 Parent-Child 切块</li><li>向量检索 + BM25 混合召回</li><li>对候选集做去重与重排</li><li>组装精简上下文</li><li>生成答案并展示引用</li><li>用日志和人工抽检反哺切块与检索策略</li></ol><p>这条链路未必最“前沿”，但通常比单纯“文档切块 + 向量库 + 大模型”稳得多。</p><h2 id="_8-常见反模式" tabindex="-1">8. 常见反模式 <a class="header-anchor" href="#_8-常见反模式" aria-label="Permalink to &quot;8. 常见反模式&quot;">​</a></h2><h3 id="_8-1-把向量库当成全部答案" tabindex="-1">8.1 把向量库当成全部答案 <a class="header-anchor" href="#_8-1-把向量库当成全部答案" aria-label="Permalink to &quot;8.1 把向量库当成全部答案&quot;">​</a></h3><p>向量库解决的是召回，不是完整的 RAG 质量问题。</p><h3 id="_8-2-只看检索分数" tabindex="-1">8.2 只看检索分数 <a class="header-anchor" href="#_8-2-只看检索分数" aria-label="Permalink to &quot;8.2 只看检索分数&quot;">​</a></h3><p>高分不等于能支撑回答。分数只是召回算法的内部信号。</p><h3 id="_8-3-候选拿太多" tabindex="-1">8.3 候选拿太多 <a class="header-anchor" href="#_8-3-候选拿太多" aria-label="Permalink to &quot;8.3 候选拿太多&quot;">​</a></h3><p>候选过多会把噪声也一并放大，未必比少量高质量候选更好。</p><h3 id="_8-4-没有来源展示" tabindex="-1">8.4 没有来源展示 <a class="header-anchor" href="#_8-4-没有来源展示" aria-label="Permalink to &quot;8.4 没有来源展示&quot;">​</a></h3><p>没有引用来源，用户很难建立信任，开发者也很难排查问题。</p><h2 id="_9-小结" tabindex="-1">9. 小结 <a class="header-anchor" href="#_9-小结" aria-label="Permalink to &quot;9. 小结&quot;">​</a></h2><p>RAG 做得好不好，关键不在“有没有向量库”，而在整条信息供应链是否合理：</p><ul><li>切块是否保住语义</li><li>召回是否兼顾语义和关键词</li><li>重排是否把真正关键证据提到前面</li><li>上下文组装是否克制而有结构</li></ul><p>当你把这些环节都拆开看，RAG 的问题就不再神秘，而会变成一组可以逐步优化的工程问题。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2005.11401" target="_blank" rel="noreferrer">Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks</a></li><li><a href="https://arxiv.org/abs/2307.03172" target="_blank" rel="noreferrer">Lost in the Middle: How Language Models Use Long Contexts</a></li><li><a href="https://cookbook.openai.com/" target="_blank" rel="noreferrer">OpenAI Cookbook</a></li><li>延伸阅读：<a href="./rag-intro.html">初探 RAG 架构</a></li></ul>`,71)])])}const k=i(r,[["render",n]]);export{c as __pageData,k as default};
